fixed_code:
fn divide(a: i32, b: i32) -> Option<i32> {
    if b == 0 { None } else { Some(a / b) }
}

fn main() {
    match divide(10, 0) {
        Some(result) => println!("Result: {}
", result),
        None => println!("Cannot divide by zero.")
    }
}

